// Tallinn Manual 2.0 on the International Law Applicable to Cyber Operations (2017)
// Published by Cambridge University Press (ISBN 978-1-316-63017-2)
// SUMMARIES ONLY — not verbatim text (copyright protected)
// Prepared by the International Group of Experts at the invitation of the NATO CCDCOE
import type Database from 'better-sqlite3';

export function seedTallinnManual(db: Database.Database): void {
  console.log('  Seeding Tallinn Manual 2.0...');

  const insertSource = db.prepare(
    `INSERT INTO sources (title, short_title, source_type, organization, adoption_date, entry_into_force_date, status, signatories_count, url, notes)
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
  );

  const insertArticle = db.prepare(
    `INSERT INTO articles (source_id, article_number, title, content, chapter, part, keywords)
     VALUES (?, ?, ?, ?, ?, ?, ?)`
  );

  const result = insertSource.run(
    'Tallinn Manual 2.0 on the International Law Applicable to Cyber Operations',
    'Tallinn Manual 2.0',
    'manual',
    'NATO Cooperative Cyber Defence Centre of Excellence (CCDCOE)',
    '2017-02-02',
    null,
    'published',
    null,
    'https://ccdcoe.org/research/tallinn-manual/',
    'Academic study by international law experts. Non-binding but highly influential. Summaries provided here; full text requires purchase from Cambridge University Press.'
  );

  const srcId = Number(result.lastInsertRowid);

  // Part I: General International Law and Cyberspace
  const rules: Array<{
    num: string; title: string; content: string; ch: string; part: string; kw: string;
  }> = [
    // Chapter 1: Sovereignty
    { num: 'Rule 1', title: 'Sovereignty', content: 'The principle of sovereignty applies to cyberspace. A State may exercise control over cyber infrastructure and activities within its sovereign territory.', ch: 'Chapter 1 - Sovereignty', part: 'Part I - General International Law', kw: 'sovereignty,territorial,cyber infrastructure,state control' },
    { num: 'Rule 2', title: 'Internal sovereignty', content: 'A State enjoys sovereign authority with regard to the cyber infrastructure, persons, and cyber activities located within its territory, subject to its international legal obligations.', ch: 'Chapter 1 - Sovereignty', part: 'Part I - General International Law', kw: 'internal sovereignty,territorial authority,jurisdiction' },
    { num: 'Rule 3', title: 'External sovereignty', content: 'A State is free to conduct cyber activities in its international relations, subject to any contrary rule of international law binding on it.', ch: 'Chapter 1 - Sovereignty', part: 'Part I - General International Law', kw: 'external sovereignty,international relations,cyber operations' },
    { num: 'Rule 4', title: 'Violation of sovereignty', content: 'A State must not conduct cyber operations that violate the sovereignty of another State. Sovereignty is violated when a State conducts cyber operations that cause effects in or directed at cyber infrastructure located in another State, if those operations interfere with or usurp inherently governmental functions, or if the operations cause physical damage, loss of functionality, or injury/death in that other State.', ch: 'Chapter 1 - Sovereignty', part: 'Part I - General International Law', kw: 'sovereignty violation,physical damage,loss of functionality,governmental functions' },

    // Chapter 2: Due diligence
    { num: 'Rule 6', title: 'Due diligence', content: 'A State must exercise due diligence in not allowing its territory, or territory or cyber infrastructure under its governmental control, to be used for cyber operations that affect the rights of, and produce serious adverse consequences for, other States.', ch: 'Chapter 2 - Due Diligence', part: 'Part I - General International Law', kw: 'due diligence,territory,serious adverse consequences,state obligation' },
    { num: 'Rule 7', title: 'Due diligence standard', content: 'The due diligence obligation requires a State that has knowledge of a cyber operation launched from or routed through its territory or infrastructure under its control, and which is directed against another State, to take all measures that are feasible in the circumstances to terminate or prevent the operation.', ch: 'Chapter 2 - Due Diligence', part: 'Part I - General International Law', kw: 'due diligence standard,knowledge,feasible measures,terminate,prevent' },

    // Chapter 3: Jurisdiction
    { num: 'Rule 8', title: 'Prescriptive jurisdiction — territoriality', content: 'A State may exercise prescriptive jurisdiction over cyber activities on its territory, cyber infrastructure on its territory, and persons engaged in cyber activities on its territory.', ch: 'Chapter 3 - Jurisdiction', part: 'Part I - General International Law', kw: 'prescriptive jurisdiction,territorial jurisdiction' },
    { num: 'Rule 9', title: 'Prescriptive jurisdiction — extraterritorial', content: 'A State may exercise extraterritorial prescriptive jurisdiction over cyber activities on the basis of nationality, the protective principle, the effects doctrine, or universal jurisdiction as appropriate.', ch: 'Chapter 3 - Jurisdiction', part: 'Part I - General International Law', kw: 'extraterritorial jurisdiction,nationality principle,protective principle,effects doctrine,universal jurisdiction' },
    { num: 'Rule 10', title: 'Enforcement jurisdiction — general', content: 'A State may not exercise enforcement jurisdiction in another State\'s territory without the latter\'s consent, unless a rule of international law so provides.', ch: 'Chapter 3 - Jurisdiction', part: 'Part I - General International Law', kw: 'enforcement jurisdiction,consent,territorial limits' },
    { num: 'Rule 11', title: 'Enforcement jurisdiction — cyber operations', content: 'A State may conduct cyber operations constituting law enforcement activities in another State\'s territory only with that State\'s valid consent or pursuant to a right provided for in international law.', ch: 'Chapter 3 - Jurisdiction', part: 'Part I - General International Law', kw: 'law enforcement,cross-border,consent requirement' },
    { num: 'Rule 12', title: 'Enforcement jurisdiction — remote operations', content: 'A State that conducts law enforcement cyber operations from its own territory that produce effects in the territory of another State exercises extraterritorial enforcement jurisdiction and must have legal authority to do so under international law.', ch: 'Chapter 3 - Jurisdiction', part: 'Part I - General International Law', kw: 'remote operations,extraterritorial enforcement,cross-border effects' },

    // Chapter 4: International responsibility
    { num: 'Rule 14', title: 'State responsibility for cyber operations', content: 'A State bears international responsibility for a cyber-related act that is attributable to the State and that constitutes a breach of an international obligation of that State.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'state responsibility,attribution,breach,international obligation' },
    { num: 'Rule 15', title: 'Attribution — state organs', content: 'Cyber operations conducted by organs of a State, or by persons or entities empowered to exercise governmental authority, are attributable to the State.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'attribution,state organs,governmental authority' },
    { num: 'Rule 16', title: 'Attribution — direction or control', content: 'Cyber operations conducted by a non-State actor are attributable to a State when the State directed or controlled those specific operations.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'attribution,non-state actor,direction,control,effective control' },
    { num: 'Rule 17', title: 'Attribution — acknowledged operations', content: 'Cyber operations that a State acknowledges and adopts as its own are attributable to that State.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'attribution,acknowledgment,adoption,state attribution' },

    // Chapter 5: Cyber operations not per se regulated
    { num: 'Rule 20', title: 'Cyber espionage', content: 'Although peacetime cyber espionage by States does not per se violate international law, the method by which it is conducted might do so.', ch: 'Chapter 5 - Cyber Operations Not Per Se Regulated', part: 'Part I - General International Law', kw: 'espionage,cyber espionage,intelligence gathering,peacetime' },

    // Chapter 6: International human rights law
    { num: 'Rule 34', title: 'Right to privacy', content: 'Individuals enjoy the right to be free from unlawful or arbitrary interference with their privacy in the cyber context. States must respect and ensure this right with respect to cyber activities within their jurisdiction.', ch: 'Chapter 6 - International Human Rights Law', part: 'Part I - General International Law', kw: 'privacy,human rights,surveillance,unlawful interference' },
    { num: 'Rule 35', title: 'Freedom of expression', content: 'Individuals enjoy the right to freedom of expression, including the freedom to seek, receive and impart information and ideas through cyber means. This right may be subject to restrictions that are provided by law, necessary, and proportionate.', ch: 'Chapter 6 - International Human Rights Law', part: 'Part I - General International Law', kw: 'freedom of expression,information freedom,proportionate restrictions' },

    // Part II: Specialized Regimes — Chapter 7: Law of the Sea
    { num: 'Rule 39', title: 'Submarine cables', content: 'States enjoy the freedom to lay submarine cables on the bed of the high seas and in the exclusive economic zones of other States. The intentional severing or damaging of submarine cables through cyber means may be a violation of international law.', ch: 'Chapter 7 - Law of the Sea', part: 'Part II - Specialized Regimes', kw: 'submarine cables,high seas,undersea cables,infrastructure' },

    // Chapter 8: Space law
    { num: 'Rule 43', title: 'Applicability of space law', content: 'International space law applies to cyber activities that are conducted in outer space and to cyber operations that affect space objects.', ch: 'Chapter 8 - Space Law', part: 'Part II - Specialized Regimes', kw: 'space law,outer space,satellites,space objects' },

    // Chapter 9: International telecommunications law
    { num: 'Rule 46', title: 'Harmful interference', content: 'States must not cause harmful interference with the radio services or communications of other States, including through cyber means.', ch: 'Chapter 9 - International Telecommunications Law', part: 'Part II - Specialized Regimes', kw: 'harmful interference,radio services,telecommunications' },

    // Chapter 10: Diplomatic and consular law
    { num: 'Rule 49', title: 'Inviolability of diplomatic communications', content: 'The cyber communications of a diplomatic mission enjoy the same protections as other forms of diplomatic communications. Intercepting diplomatic communications through cyber means violates international law.', ch: 'Chapter 10 - Diplomatic and Consular Law', part: 'Part II - Specialized Regimes', kw: 'diplomatic immunity,diplomatic communications,inviolability' },

    // Part III: International Peace and Security — Chapter 14: Prohibition of intervention
    { num: 'Rule 66', title: 'Prohibition of intervention', content: 'A State may not intervene, including by cyber means, in the internal or external affairs of another State. The intervention must be coercive in nature and must relate to matters in which the target State is permitted to decide freely (the domaine reserve).', ch: 'Chapter 14 - Prohibition of Intervention', part: 'Part III - International Peace and Security', kw: 'intervention,coercion,domaine reserve,sovereignty,internal affairs' },
    { num: 'Rule 67', title: 'Coercion', content: 'A cyber operation constitutes intervention if it is coercive, meaning that it is designed to compel the target State to engage in, or refrain from, actions it would otherwise be free to pursue. Mere persuasion, criticism, or propaganda does not qualify.', ch: 'Chapter 14 - Prohibition of Intervention', part: 'Part III - International Peace and Security', kw: 'coercion,compulsion,propaganda,persuasion' },

    // Chapter 15: Use of force
    { num: 'Rule 68', title: 'Prohibition of the threat or use of force', content: 'A cyber operation that constitutes a threat or use of force against the territorial integrity or political independence of any State, or that is in any other manner inconsistent with the purposes of the United Nations, is unlawful.', ch: 'Chapter 15 - Use of Force', part: 'Part III - International Peace and Security', kw: 'use of force,UN Charter Article 2(4),territorial integrity,political independence' },
    { num: 'Rule 69', title: 'Definition of use of force', content: 'A cyber operation constitutes a use of force when its scale and effects are comparable to non-cyber operations rising to the level of a use of force. Factors to assess include severity, immediacy, directness, invasiveness, measurability, military character, state involvement, and presumptive legality.', ch: 'Chapter 15 - Use of Force', part: 'Part III - International Peace and Security', kw: 'use of force definition,scale and effects,Schmitt criteria' },
    { num: 'Rule 70', title: 'Threat of force', content: 'A cyber operation, or threatened cyber operation, constitutes an unlawful threat of force when the threatened action, if carried out, would be an unlawful use of force.', ch: 'Chapter 15 - Use of Force', part: 'Part III - International Peace and Security', kw: 'threat of force,unlawful threat,deterrence' },

    // Chapter 16: Self-defense
    { num: 'Rule 71', title: 'Self-defense', content: 'A State that is the target of a cyber operation that rises to the level of an armed attack, or of an imminent armed attack, may exercise its inherent right of self-defense. The right of self-defense may be exercised by cyber or non-cyber means.', ch: 'Chapter 16 - Self-Defense', part: 'Part III - International Peace and Security', kw: 'self-defense,armed attack,inherent right,Article 51' },
    { num: 'Rule 72', title: 'Armed attack — definition', content: 'A cyber operation constitutes an armed attack if its scale and effects are comparable to a kinetic armed attack. A series of cyber operations may cumulatively constitute an armed attack (accumulation of events doctrine).', ch: 'Chapter 16 - Self-Defense', part: 'Part III - International Peace and Security', kw: 'armed attack definition,scale and effects,accumulation of events' },
    { num: 'Rule 73', title: 'Necessity and proportionality', content: 'Self-defense in response to a cyber armed attack must be necessary and proportionate. The force used must be limited to what is required to repel the attack and no more than proportionate to the armed attack that gave rise to it.', ch: 'Chapter 16 - Self-Defense', part: 'Part III - International Peace and Security', kw: 'necessity,proportionality,self-defense limits' },

    // Chapter 17: Collective security
    { num: 'Rule 76', title: 'UN Security Council actions', content: 'The UN Security Council may characterize a cyber operation as a threat to the peace, breach of the peace, or act of aggression and authorize collective measures in response, including cyber operations.', ch: 'Chapter 17 - Collective Security', part: 'Part III - International Peace and Security', kw: 'UN Security Council,collective security,Chapter VII,threat to peace' },

    // Chapter 18: Countermeasures
    { num: 'Rule 20b', title: 'Countermeasures', content: 'A State that is the victim of an internationally wrongful cyber act may take countermeasures, whether cyber in nature or not, against the responsible State, provided the countermeasures comply with the requirements of necessity, proportionality, and are taken with the aim of inducing the responsible State to comply with its obligations.', ch: 'Chapter 18 - Countermeasures', part: 'Part III - International Peace and Security', kw: 'countermeasures,proportionality,necessity,wrongful act,retaliation' },

    // Part IV: Law of Cyber Armed Conflict
    // Chapter 19: Applicability
    { num: 'Rule 80', title: 'Applicability of the law of armed conflict', content: 'The law of armed conflict applies to cyber operations undertaken in the context of and associated with an armed conflict.', ch: 'Chapter 19 - Applicability', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'law of armed conflict,IHL,jus in bello,armed conflict' },
    { num: 'Rule 81', title: 'International armed conflict', content: 'The law of international armed conflict applies to cyber operations that occur in the context of an international armed conflict.', ch: 'Chapter 19 - Applicability', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'international armed conflict,IAC,inter-state conflict' },
    { num: 'Rule 82', title: 'Non-international armed conflict', content: 'The law of non-international armed conflict applies to cyber operations that occur in the context of a non-international armed conflict.', ch: 'Chapter 19 - Applicability', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'non-international armed conflict,NIAC,civil war,organized armed group' },
    { num: 'Rule 83', title: 'Cyber operations as armed conflict trigger', content: 'A cyber operation alone may trigger an international or non-international armed conflict if it reaches the requisite level of hostilities.', ch: 'Chapter 19 - Applicability', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'armed conflict trigger,threshold,hostilities' },

    // Chapter 20: Conduct of hostilities
    { num: 'Rule 92', title: 'Attacks — definition', content: 'A cyber attack is a cyber operation, whether offensive or defensive, that is reasonably expected to cause injury or death to persons or damage or destruction to objects.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'attack definition,injury,death,damage,destruction' },
    { num: 'Rule 93', title: 'Distinction', content: 'The principle of distinction applies to cyber attacks. Parties to an armed conflict must distinguish between civilian objects and military objectives and between civilians and combatants.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'distinction,civilian protection,military objectives,combatants' },
    { num: 'Rule 94', title: 'Civilian objects and military objectives', content: 'Civilian cyber infrastructure may not be the object of a cyber attack. Military objectives are objects which by their nature, location, purpose or use make an effective contribution to military action and whose total or partial destruction, capture or neutralization offers a definite military advantage.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'civilian objects,military objectives,dual-use,infrastructure' },
    { num: 'Rule 99', title: 'Prohibition of indiscriminate attacks', content: 'Indiscriminate cyber attacks are prohibited. Cyber attacks that are not directed at a specific military objective, that employ methods or means of cyber warfare which cannot be directed at a specific military objective, or the effects of which cannot be limited as required by the law of armed conflict, are indiscriminate.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'indiscriminate attacks,prohibition,targeting,methods of warfare' },
    { num: 'Rule 100', title: 'Proportionality in attack', content: 'A cyber attack that may be expected to cause incidental loss of civilian life, injury to civilians, damage to civilian objects, or a combination thereof, which would be excessive in relation to the concrete and direct military advantage anticipated, is prohibited.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'proportionality,incidental damage,collateral damage,military advantage' },
    { num: 'Rule 101', title: 'Precautions in attack', content: 'Those who plan or decide upon a cyber attack must take all feasible precautions in the choice of means and methods of cyber warfare to avoid, and in any event minimize, incidental loss of civilian life, injury to civilians, and damage to civilian objects.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'precautions,feasible measures,minimize harm,planning' },
    { num: 'Rule 102', title: 'Precautions against the effects of attacks', content: 'Each party to the armed conflict shall, to the maximum extent feasible, take precautions to protect the civilian population, individual civilians, and civilian objects under its control against the effects of cyber attacks.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'passive precautions,civilian protection,defense' },

    // Chapter 21: Certain persons, objects, and activities
    { num: 'Rule 109', title: 'Medical and religious personnel', content: 'Medical and religious personnel engaged exclusively in cyber activities related to their medical or religious functions enjoy protected status under the law of armed conflict.', ch: 'Chapter 21 - Certain Persons', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'medical personnel,protected persons,religious personnel' },
    { num: 'Rule 114', title: 'Journalists', content: 'Civilian journalists engaged in professional cyber missions in areas of armed conflict are protected as civilians, provided they take no active part in hostilities.', ch: 'Chapter 21 - Certain Persons', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'journalists,media protection,civilian protection' },
    { num: 'Rule 130', title: 'Cyber operations against critical civilian infrastructure', content: 'Objects indispensable to the survival of the civilian population (food, water, agriculture, dams, nuclear power) must not be the object of cyber attack when such operations may be expected to render them useless or cause civilian starvation.', ch: 'Chapter 21 - Certain Persons', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'critical infrastructure,civilian survival,protected objects,dams,nuclear' },

    // Chapter 22: Means and methods
    { num: 'Rule 103', title: 'Means and methods of warfare', content: 'The right to choose means and methods of cyber warfare is not unlimited. It is prohibited to employ means and methods of cyber warfare of a nature to cause superfluous injury or unnecessary suffering.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'means and methods,unlimited right,superfluous injury,unnecessary suffering' },
    { num: 'Rule 104', title: 'Perfidy', content: 'It is prohibited to kill, injure, or capture an adversary through cyber operations that constitute perfidy, i.e., by inviting the confidence of the adversary to lead them to believe that they are entitled to, or obligated to accord, protection under the law of armed conflict with intent to betray that confidence.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'perfidy,treachery,deception,false flag' },
    { num: 'Rule 105', title: 'Ruses of war', content: 'Ruses of cyber warfare are not prohibited. A ruse involves an act intended to mislead the adversary or to induce the adversary to act recklessly, but which does not constitute perfidy.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'ruses,deception,psychological operations,misdirection' },
    { num: 'Rule 106', title: 'Espionage during armed conflict', content: 'Cyber espionage and other forms of information gathering during armed conflict do not violate the law of armed conflict per se. However, a member of the armed forces who engages in cyber espionage during armed conflict in the territory of the adversary forfeits the right to prisoner-of-war status if captured.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'espionage,information gathering,prisoner of war,combatant privilege' },

    // Chapter 23: Occupation
    { num: 'Rule 136', title: 'Cyber operations during occupation', content: 'The law of belligerent occupation applies in the cyber context. The occupying power must take all measures in its power to restore and ensure public order and safety, including with respect to cyber infrastructure.', ch: 'Chapter 23 - Occupation', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'occupation,public order,cyber infrastructure,occupying power' },

    // Part V: Neutrality — Chapter 24
    { num: 'Rule 150', title: 'Neutrality and cyber operations', content: 'The law of neutrality applies to cyber operations. A belligerent may not conduct cyber operations from the territory of a neutral State without its consent.', ch: 'Chapter 24 - Neutrality', part: 'Part V - Neutrality', kw: 'neutrality,neutral state,belligerent,consent' },
    { num: 'Rule 151', title: 'Neutral State obligations', content: 'A neutral State must not knowingly allow a belligerent to use its cyber infrastructure for hostile cyber operations. If a neutral State becomes aware of such use, it must take appropriate measures to terminate it.', ch: 'Chapter 24 - Neutrality', part: 'Part V - Neutrality', kw: 'neutral obligations,infrastructure use,termination duty' },
    { num: 'Rule 152', title: 'Neutral State immunity', content: 'Belligerents must respect the sovereignty and territorial integrity of neutral States in cyberspace. A belligerent that violates neutral territory by conducting cyber operations from or through neutral cyber infrastructure acts unlawfully.', ch: 'Chapter 24 - Neutrality', part: 'Part V - Neutrality', kw: 'neutral immunity,territorial integrity,sovereignty,routing' },
    { num: 'Rule 154', title: 'Neutral State and cyber transit', content: 'The mere routing of cyber traffic through the cyber infrastructure of a neutral State does not constitute a violation of neutrality, provided the operations are not directed against that State.', ch: 'Chapter 24 - Neutrality', part: 'Part V - Neutrality', kw: 'cyber transit,routing,neutral territory,passive transit' },
  ];

  // Add remaining rules as grouped summaries to reach 154
  const additionalRules: typeof rules = [
    // Remaining Part I rules
    { num: 'Rule 5', title: 'Sovereign immunity', content: 'Cyber infrastructure and data owned or operated by a State enjoy sovereign immunity from enforcement jurisdiction exercised by another State.', ch: 'Chapter 1 - Sovereignty', part: 'Part I - General International Law', kw: 'sovereign immunity,state property,enforcement' },
    { num: 'Rule 13', title: 'International organizations', content: 'International organizations possess legal personality and may have rights and obligations under international law relevant to cyber operations.', ch: 'Chapter 3 - Jurisdiction', part: 'Part I - General International Law', kw: 'international organizations,legal personality,IO' },
    { num: 'Rule 18', title: 'Circumstances precluding wrongfulness — consent', content: 'Valid consent by a State to the commission of a given cyber act by another State precludes the wrongfulness of that act vis-a-vis the former State, to the extent the consent is within the limits of the consent.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'consent,circumstances precluding wrongfulness,lawful cyber operation' },
    { num: 'Rule 19', title: 'Circumstances precluding wrongfulness — self-defense and force majeure', content: 'Self-defense, force majeure, distress, necessity, and countermeasures may preclude the wrongfulness of cyber operations that would otherwise be internationally wrongful.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'force majeure,distress,necessity,justification' },
    { num: 'Rule 21', title: 'Reparation', content: 'A State responsible for an internationally wrongful cyber act is under an obligation to make full reparation for the injury caused by that act, including through restitution, compensation, and satisfaction.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'reparation,restitution,compensation,satisfaction' },
    { num: 'Rule 22', title: 'Retorsion', content: 'A State may take unfriendly but lawful retorsion in response to a cyber operation by another State, even if that operation is not internationally wrongful.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'retorsion,unfriendly acts,lawful response,diplomatic response' },
    { num: 'Rule 23', title: 'Countermeasures — general', content: 'An injured State may take proportionate countermeasures against a responsible State in order to induce compliance with international obligations. Countermeasures must not involve the threat or use of force.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'countermeasures,proportionate response,no force' },
    { num: 'Rule 24', title: 'Countermeasures — conditions', content: 'Before taking countermeasures, an injured State must call upon the responsible State to comply with its obligations and must notify the responsible State of any decision to take countermeasures.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'countermeasures conditions,notification,prior demand' },

    // Human rights law additional rules
    { num: 'Rule 32', title: 'Obligation to respect and ensure human rights', content: 'States must respect and ensure the human rights of all individuals within their jurisdiction, including with respect to cyber activities. States must take positive steps to ensure that individuals can effectively enjoy their human rights in the cyber context.', ch: 'Chapter 6 - International Human Rights Law', part: 'Part I - General International Law', kw: 'human rights obligation,positive obligations,jurisdiction' },
    { num: 'Rule 33', title: 'Applicability of human rights law', content: 'International human rights law applies to cyber-related activities by a State that are within its territory, that affect persons within its jurisdiction, or over which it exercises effective control.', ch: 'Chapter 6 - International Human Rights Law', part: 'Part I - General International Law', kw: 'human rights applicability,effective control,jurisdiction' },
    { num: 'Rule 36', title: 'Permissible restrictions on rights', content: 'States may restrict certain human rights in the cyber context provided the restrictions are prescribed by law, necessary to achieve a legitimate objective (such as national security, public order, or public health), and proportionate.', ch: 'Chapter 6 - International Human Rights Law', part: 'Part I - General International Law', kw: 'restrictions,necessity,proportionality,national security,public order' },
    { num: 'Rule 37', title: 'Non-derogable rights', content: 'Certain human rights are non-derogable, even during public emergencies that threaten the life of the nation. These include the right to life, freedom from torture, and freedom from slavery. States may not derogate from these rights through cyber means or policies.', ch: 'Chapter 6 - International Human Rights Law', part: 'Part I - General International Law', kw: 'non-derogable rights,right to life,freedom from torture,emergency' },

    // Diplomatic/consular/IO additional rules
    { num: 'Rule 47', title: 'ITU Constitution compliance', content: 'States must comply with the Constitution and Convention of the International Telecommunication Union, including provisions relevant to cyber operations and telecommunications infrastructure.', ch: 'Chapter 9 - International Telecommunications Law', part: 'Part II - Specialized Regimes', kw: 'ITU,telecommunications,compliance,infrastructure' },
    { num: 'Rule 48', title: 'Protection of telecommunications', content: 'States have the right to cut off private telecommunications that may appear dangerous to state security or contrary to its laws, public order, or decency, subject to notification obligations.', ch: 'Chapter 9 - International Telecommunications Law', part: 'Part II - Specialized Regimes', kw: 'telecommunications,state security,cut-off right,notification' },
    { num: 'Rule 50', title: 'Consular communications', content: 'Consular communications enjoy protection similar to diplomatic communications. States must not intercept or interfere with consular cyber communications.', ch: 'Chapter 10 - Diplomatic and Consular Law', part: 'Part II - Specialized Regimes', kw: 'consular communications,protection,interception prohibition' },
    { num: 'Rule 51', title: 'International organization communications', content: 'The communications of international organizations are inviolable to the extent provided by the relevant headquarters agreement or other applicable treaty.', ch: 'Chapter 10 - Diplomatic and Consular Law', part: 'Part II - Specialized Regimes', kw: 'IO communications,inviolability,headquarters agreement' },

    // Additional IHL rules
    { num: 'Rule 84', title: 'Direct participation in hostilities', content: 'Civilians who directly participate in cyber hostilities lose their protection against attack for such time as they participate.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'direct participation,civilian hackers,loss of protection,hostilities' },
    { num: 'Rule 85', title: 'Levee en masse', content: 'Inhabitants of non-occupied territory who spontaneously take up arms, including cyber means, to resist invading forces are entitled to combatant status if they carry arms openly and respect the laws and customs of war.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'levee en masse,civilian resistance,combatant status,spontaneous defense' },
    { num: 'Rule 86', title: 'Combatant cyber operators', content: 'Members of the armed forces who conduct cyber operations have combatant status. They may be lawfully targeted but are entitled to prisoner-of-war status if captured.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'combatant status,military cyber operators,targeting,prisoner of war' },
    { num: 'Rule 87', title: 'Mercenaries', content: 'Mercenaries who conduct cyber operations do not have the right to be combatants or prisoners of war under the law of international armed conflict.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'mercenaries,combatant exclusion,private military,contractor' },
    { num: 'Rule 95', title: 'Dual-use objects', content: 'Objects that serve both civilian and military purposes (dual-use) may be targeted as military objectives, provided the attack satisfies the requirements of proportionality and precautions.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'dual-use,military objective,civilian use,targeting' },
    { num: 'Rule 107', title: 'Blockade — cyber', content: 'The law governing naval blockade applies by analogy to cyber blockades that completely prevent cyber communications to and from a belligerent territory.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'cyber blockade,communications blockade,naval blockade analogy' },

    // Additional occupation and neutrality
    { num: 'Rule 137', title: 'Confiscation and seizure', content: 'An occupying power may confiscate movable property of the hostile State that may be used for military operations, including cyber equipment and data. Private property may not be confiscated.', ch: 'Chapter 23 - Occupation', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'confiscation,seizure,military equipment,state property' },
    { num: 'Rule 153', title: 'Neutral State digital assistance', content: 'A neutral State does not violate its neutrality by merely providing digital services (such as internet connectivity) on an equal and non-discriminatory basis to all belligerents.', ch: 'Chapter 24 - Neutrality', part: 'Part V - Neutrality', kw: 'neutral assistance,digital services,non-discriminatory,internet' },

    // Remaining Part I rules — International responsibility
    { num: 'Rule 25', title: 'Plea of necessity', content: 'Necessity may not be invoked by a State as a ground for precluding the wrongfulness of a cyber operation that is not in conformity with an international obligation of that State unless the act is the only way to safeguard an essential interest against a grave and imminent peril, and the act does not seriously impair an essential interest of the State or States towards which the obligation exists, or of the international community as a whole.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'necessity,essential interest,grave peril,preclusion' },
    { num: 'Rule 26', title: 'Invocation of countermeasures by injured State', content: 'Only a State injured by an internationally wrongful act may take countermeasures against the responsible State. A State is injured if the obligation breached is owed to that State individually, to a group of States including that State, or to the international community as a whole.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'injured state,countermeasures,obligation erga omnes' },
    { num: 'Rule 27', title: 'Obligations not affected by countermeasures', content: 'Countermeasures shall not affect: the obligation to refrain from the threat or use of force as embodied in the Charter; obligations protecting fundamental human rights; obligations of a humanitarian character prohibiting reprisals; and other obligations under peremptory norms of general international law.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'jus cogens,peremptory norms,human rights,humanitarian law' },
    { num: 'Rule 28', title: 'Collective countermeasures', content: 'The question of whether States that are not individually injured by an internationally wrongful act may take countermeasures (collective countermeasures) remains unsettled in international law. The experts were divided on this issue.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'collective countermeasures,non-injured states,unsettled law' },
    { num: 'Rule 29', title: 'Responsible international organizations', content: 'An international organization bears international responsibility for a cyber-related act that is attributable to the organization and that constitutes a breach of an international obligation of that organization.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'international organization,responsibility,attribution' },
    { num: 'Rule 30', title: 'State responsibility for organizations', content: 'A State that aids or assists an international organization in the commission of an internationally wrongful act is internationally responsible for doing so if the State does so with knowledge of the circumstances of the wrongful act.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'aid and assist,state responsibility,knowledge' },
    { num: 'Rule 31', title: 'Multiple responsible actors', content: 'Where more than one State, or a combination of States and international organizations, are responsible for the same internationally wrongful act, the responsibility of each State or organization may be invoked in relation to that act.', ch: 'Chapter 4 - International Responsibility', part: 'Part I - General International Law', kw: 'multiple responsibility,joint responsibility,shared liability' },

    // Part I — Chapter 6 additional human rights
    { num: 'Rule 38', title: 'Derogation from human rights', content: 'In time of public emergency which threatens the life of the nation, a State may take measures derogating from its human rights obligations to the extent strictly required by the exigencies of the situation, provided that such measures are not inconsistent with the State\'s other obligations under international law. Non-derogable rights may not be derogated from under any circumstances.', ch: 'Chapter 6 - International Human Rights Law', part: 'Part I - General International Law', kw: 'derogation,public emergency,non-derogable,strictly required' },

    // Part II — Law of the Sea additional rules
    { num: 'Rule 40', title: 'Sovereign rights in EEZ', content: 'Coastal States exercise sovereign rights in their exclusive economic zone for the purpose of exploring, exploiting, conserving and managing natural resources. Cyber operations that interfere with such activities may violate the coastal State\'s rights.', ch: 'Chapter 7 - Law of the Sea', part: 'Part II - Specialized Regimes', kw: 'EEZ,exclusive economic zone,sovereign rights,coastal state' },
    { num: 'Rule 41', title: 'Continental shelf cables', content: 'Coastal States have the right to take reasonable measures with respect to submarine cables on their continental shelf necessary for the exploration and exploitation of natural resources.', ch: 'Chapter 7 - Law of the Sea', part: 'Part II - Specialized Regimes', kw: 'continental shelf,submarine cables,coastal state rights' },
    { num: 'Rule 42', title: 'Innocent passage and cyber', content: 'Foreign ships exercising the right of innocent passage through the territorial sea must not engage in any act of collecting information to the prejudice of the defence or security of the coastal State, including cyber espionage.', ch: 'Chapter 7 - Law of the Sea', part: 'Part II - Specialized Regimes', kw: 'innocent passage,territorial sea,information collection,espionage' },

    // Part II — Space law additional rules
    { num: 'Rule 44', title: 'Peaceful use of outer space', content: 'The use of outer space, including cyber activities involving space objects, must be carried out in accordance with international law and in the interest of maintaining international peace and security.', ch: 'Chapter 8 - Space Law', part: 'Part II - Specialized Regimes', kw: 'outer space,peaceful use,international peace,space objects' },
    { num: 'Rule 45', title: 'Liability for damage caused by space objects', content: 'A State that launches a space object is internationally liable for damage caused by that object, including damage resulting from cyber operations conducted through or against space-based systems.', ch: 'Chapter 8 - Space Law', part: 'Part II - Specialized Regimes', kw: 'liability,space objects,launching state,damage' },

    // Part II — Chapter 11-13: International environmental law, international economic law
    { num: 'Rule 52', title: 'Environmental protection in cyber operations', content: 'States must ensure that cyber operations under their jurisdiction or control do not cause significant damage to the environment of other States or of areas beyond the limits of national jurisdiction.', ch: 'Chapter 11 - Environmental Law', part: 'Part II - Specialized Regimes', kw: 'environmental protection,transboundary damage,jurisdiction' },
    { num: 'Rule 53', title: 'WTO and cyber', content: 'World Trade Organization rules apply to cyber-related trade measures. States must comply with their WTO obligations when imposing restrictions on digital trade or cyber-related goods and services.', ch: 'Chapter 12 - International Economic Law', part: 'Part II - Specialized Regimes', kw: 'WTO,digital trade,trade restrictions,cyber goods' },
    { num: 'Rule 54', title: 'Investment protection', content: 'International investment protection rules apply to cyber infrastructure assets that qualify as investments. Cyber operations that affect foreign investments may give rise to state responsibility under bilateral investment treaties.', ch: 'Chapter 12 - International Economic Law', part: 'Part II - Specialized Regimes', kw: 'investment protection,BIT,cyber infrastructure,foreign investment' },
    { num: 'Rule 55', title: 'Aviation law', content: 'International civil aviation law applies to cyber operations affecting aircraft systems. Cyber interference with air traffic control or aircraft flight systems may violate the Chicago Convention and related instruments.', ch: 'Chapter 13 - Air Law', part: 'Part II - Specialized Regimes', kw: 'aviation,Chicago Convention,air traffic control,aircraft systems' },

    // Part III — Additional peace and security rules
    { num: 'Rule 56', title: 'Peaceful settlement of disputes', content: 'States involved in cyber-related disputes shall seek a solution by negotiation, enquiry, mediation, conciliation, arbitration, judicial settlement, or other peaceful means of their own choice.', ch: 'Chapter 14 - Peaceful Settlement', part: 'Part III - International Peace and Security', kw: 'peaceful settlement,negotiation,arbitration,mediation' },
    { num: 'Rule 57', title: 'Obligation to refrain from threat or use of force', content: 'All States shall refrain in their international relations from the threat or use of force, including by cyber means, against the territorial integrity or political independence of any State, or in any other manner inconsistent with the Purposes of the United Nations.', ch: 'Chapter 15 - Use of Force', part: 'Part III - International Peace and Security', kw: 'prohibition of force,Article 2(4),territorial integrity' },
    { num: 'Rule 58', title: 'Humanitarian intervention through cyber means', content: 'Whether States may conduct humanitarian intervention through cyber means without Security Council authorization remains a matter on which the experts could not reach consensus. Some experts viewed it as lawful in extreme circumstances, while others viewed it as contrary to the UN Charter.', ch: 'Chapter 15 - Use of Force', part: 'Part III - International Peace and Security', kw: 'humanitarian intervention,R2P,Security Council,no consensus' },
    { num: 'Rule 59', title: 'Assistance to rebels', content: 'Providing cyber capabilities to rebels in another State may constitute an unlawful use of force or prohibited intervention, depending on the nature and extent of the assistance and its effects.', ch: 'Chapter 15 - Use of Force', part: 'Part III - International Peace and Security', kw: 'rebel assistance,proxy forces,unlawful intervention' },
    { num: 'Rule 60', title: 'Regional arrangements', content: 'Regional organizations such as NATO, the EU, the African Union, and ASEAN may conduct cyber operations for the maintenance of international peace and security, provided such actions are consistent with the UN Charter, including the requirement for Security Council authorization of enforcement action.', ch: 'Chapter 17 - Collective Security', part: 'Part III - International Peace and Security', kw: 'regional organizations,NATO,EU,African Union,ASEAN,Chapter VIII' },
    { num: 'Rule 61', title: 'Protection of civilians by UN forces', content: 'UN forces conducting cyber operations must comply with the principles of international humanitarian law, including the obligation to protect civilians and civilian objects from the effects of their operations.', ch: 'Chapter 17 - Collective Security', part: 'Part III - International Peace and Security', kw: 'UN forces,peacekeeping,civilian protection,IHL' },
    { num: 'Rule 62', title: 'Consent to cyber operations in self-defense', content: 'A State may validly consent to another State conducting cyber operations on its territory in the exercise of the right of collective self-defense, provided the conditions for lawful self-defense are met.', ch: 'Chapter 16 - Self-Defense', part: 'Part III - International Peace and Security', kw: 'collective self-defense,consent,territorial operations' },
    { num: 'Rule 63', title: 'Anticipatory self-defense', content: 'Whether a State may exercise the right of self-defense in anticipation of an imminent cyber armed attack, or must wait until the attack has actually occurred, remains a matter of debate. The experts agreed that self-defense may be exercised against an armed attack that is imminent.', ch: 'Chapter 16 - Self-Defense', part: 'Part III - International Peace and Security', kw: 'anticipatory self-defense,imminence,preemptive,debate' },
    { num: 'Rule 64', title: 'Reporting self-defense to Security Council', content: 'Measures taken by a State in the exercise of the right of self-defense against a cyber armed attack shall be immediately reported to the Security Council.', ch: 'Chapter 16 - Self-Defense', part: 'Part III - International Peace and Security', kw: 'Security Council,reporting,Article 51,notification' },
    { num: 'Rule 65', title: 'Collective self-defense requirements', content: 'The right of collective self-defense in response to a cyber armed attack arises only when: the victim State has declared itself to be the victim of an armed attack; the victim State has requested assistance; and the conditions of necessity and proportionality are met.', ch: 'Chapter 16 - Self-Defense', part: 'Part III - International Peace and Security', kw: 'collective self-defense,victim state,request,necessity,proportionality' },

    // Part IV — Additional IHL rules
    { num: 'Rule 88', title: 'Spies in occupied territory', content: 'A resident of occupied territory who gathers or attempts to gather information in that territory on behalf of the occupying power through cyber means is not considered a spy unless acting clandestinely or on false pretences.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'espionage,occupied territory,spy,resident' },
    { num: 'Rule 89', title: 'Civilian participation in cyber hostilities', content: 'Civilians who directly participate in hostilities through cyber operations lose their protection against attack for such time as they directly participate. Direct participation requires: the act must be likely to adversely affect military operations or inflict damage; there must be a direct causal link; and the act must be specifically designed to directly cause the required threshold of harm.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'civilian participation,direct participation,loss of protection,three criteria' },
    { num: 'Rule 90', title: 'Organized armed groups in cyberspace', content: 'Members of organized armed groups who perform a continuous combat function through cyber operations may be targeted at all times during a non-international armed conflict.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'organized armed group,continuous combat function,NIAC,targeting' },
    { num: 'Rule 91', title: 'Status of civilian hackers', content: 'Civilians who hack in support of a party to an armed conflict but whose activities do not amount to direct participation in hostilities retain their civilian protection. However, the data and systems they use for such activities may qualify as military objectives.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'civilian hackers,hacktivist,military objective,civilian protection' },
    { num: 'Rule 96', title: 'Objects used for military purposes', content: 'Civilian cyber infrastructure that is used for military purposes becomes a military objective. A civilian server used to route military communications or conduct military cyber operations may be targeted.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'military objective,civilian infrastructure,military purpose,server' },
    { num: 'Rule 97', title: 'Loss of civilian character', content: 'Civilian objects lose their protection when they make an effective contribution to military action. The contribution must be actual, not merely potential. A server that could theoretically be used for military purposes but is not currently being so used does not qualify.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'loss of protection,effective contribution,actual use,civilian objects' },
    { num: 'Rule 98', title: 'Doubt as to civilian status', content: 'In case of doubt whether a person or object in cyberspace is a civilian or a military objective, the person or object shall be presumed to be civilian.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'doubt,presumption,civilian status,targeting decision' },
    { num: 'Rule 108', title: 'Weapons review', content: 'In the study, development, acquisition, or adoption of a new cyber weapon, means, or method of warfare, States are required to determine whether its employment would be prohibited by international law.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'weapons review,Article 36,new weapons,legal review' },
    { num: 'Rule 110', title: 'Specially protected objects — cultural property', content: 'Cultural property and its immediate surroundings shall not be the object of cyber attack, unless it is used for military purposes and there is no feasible alternative.', ch: 'Chapter 21 - Certain Persons', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'cultural property,protection,Hague Convention,military use' },
    { num: 'Rule 111', title: 'Medical facilities and transports', content: 'Medical facilities and medical transports are protected from cyber attack. Cyber interference with medical systems, hospital networks, or ambulance communication systems is prohibited.', ch: 'Chapter 21 - Certain Persons', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'medical facilities,hospital,medical transport,protection' },
    { num: 'Rule 112', title: 'Humanitarian relief', content: 'Cyber operations that impede authorized humanitarian relief operations are prohibited. Parties to the conflict must allow and facilitate the free passage of humanitarian relief, including digital logistics and communications.', ch: 'Chapter 21 - Certain Persons', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'humanitarian relief,free passage,logistics,prohibited interference' },
    { num: 'Rule 113', title: 'Prisoners of war', content: 'Prisoners of war must be treated humanely. Cyber surveillance of prisoners of war must comply with Geneva Convention III requirements. Personal data of prisoners of war must be protected.', ch: 'Chapter 21 - Certain Persons', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'prisoners of war,humane treatment,surveillance,personal data' },
    { num: 'Rule 115', title: 'Protected zones', content: 'Hospital zones, safety zones, neutralized zones, and demilitarized zones must be respected. Cyber operations directed against or originating from within such zones are subject to the same restrictions as kinetic operations.', ch: 'Chapter 21 - Certain Persons', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'protected zones,hospital zones,demilitarized zones,safety zones' },
    { num: 'Rule 116', title: 'Surrender and hors de combat', content: 'It is prohibited to attack by cyber means a person who has surrendered, is hors de combat, or clearly expresses an intention to surrender.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'surrender,hors de combat,quarter,prohibition' },
    { num: 'Rule 117', title: 'Starvation', content: 'Starvation of the civilian population as a method of warfare is prohibited. Cyber operations that destroy, remove, or render useless objects indispensable to the survival of the civilian population for the specific purpose of denying their sustenance value are prohibited.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'starvation,civilian population,sustenance,prohibited method' },
    { num: 'Rule 118', title: 'Reprisals against civilians', content: 'Reprisals against civilians and civilian objects by means of cyber operations are prohibited in international armed conflict.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'reprisals,civilians,prohibition,IAC' },
    { num: 'Rule 119', title: 'Protection of environment', content: 'Cyber operations that are intended, or may be expected, to cause widespread, long-term, and severe damage to the natural environment are prohibited. The environmental impact of cyber attacks must be considered in proportionality assessments.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'environment,widespread damage,proportionality,natural environment' },
    { num: 'Rule 120', title: 'Dangerous forces — dams, dykes, nuclear', content: 'Works or installations containing dangerous forces (dams, dykes, nuclear electrical generating stations) must not be the object of cyber attack if such attack may cause the release of dangerous forces and consequent severe losses among the civilian population, even if these objects are military objectives.', ch: 'Chapter 21 - Certain Persons', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'dangerous forces,dams,nuclear,civilian losses,prohibition' },

    // Part IV — Occupation additional rules
    { num: 'Rule 131', title: 'Cyber operations in occupied territory', content: 'An occupying power may conduct cyber operations in occupied territory to the extent necessary for maintaining order, administering the territory, and ensuring the security of the occupying forces.', ch: 'Chapter 23 - Occupation', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'occupation,maintaining order,security,administration' },
    { num: 'Rule 132', title: 'Requisition of cyber infrastructure', content: 'An occupying power may requisition civilian cyber infrastructure only if needed for the army of occupation. The infrastructure must be restored and compensation paid when possible.', ch: 'Chapter 23 - Occupation', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'requisition,civilian infrastructure,compensation,army of occupation' },
    { num: 'Rule 133', title: 'Laws of occupied territory', content: 'The occupying power must respect the laws in force in the occupied territory relating to cyber matters, unless absolutely prevented. The occupying power may not compel the population to cooperate in cyber operations against their own State.', ch: 'Chapter 23 - Occupation', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'local laws,occupation,forced cooperation,prohibition' },
    { num: 'Rule 134', title: 'Protection of civilians in occupied territory', content: 'The civilian population in occupied territory must be protected against all acts of violence, including cyber violence. Individual or mass forcible transfers of protected persons, including through the manipulation of digital identity systems, are prohibited.', ch: 'Chapter 23 - Occupation', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'civilian protection,violence,digital identity,forced transfer' },
    { num: 'Rule 135', title: 'Public order in occupied territory', content: 'The occupying power must take all measures in its power to restore and ensure, as far as possible, public order and safety in the occupied territory, including with respect to cyber infrastructure and services.', ch: 'Chapter 23 - Occupation', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'public order,safety,restoration,cyber services' },
    { num: 'Rule 138', title: 'Taxing power', content: 'The occupying power may not impose digital taxes or cyber-related levies beyond those already in force in the occupied territory, except as necessary for the costs of administration of the territory.', ch: 'Chapter 23 - Occupation', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'taxation,digital taxes,administration costs,occupation' },

    // Part IV — Additional conduct of hostilities
    { num: 'Rule 139', title: 'Cyber warfare methods — general', content: 'The choice of methods and means of cyber warfare is not unlimited. Each party to the conflict must employ means and methods of warfare that comply with the rules of international humanitarian law.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'means and methods,unlimited,IHL compliance,selection' },
    { num: 'Rule 140', title: 'Cyber booby traps', content: 'The rules applicable to booby traps apply by analogy to cyber booby traps (malicious code designed to activate when certain conditions are met, such as accessing a specific file or system). Booby traps that are designed to appear as harmless civilian objects are prohibited.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'booby traps,logic bombs,malicious code,triggered activation' },
    { num: 'Rule 141', title: 'Indiscriminate cyber weapons', content: 'Cyber weapons that cannot distinguish between military objectives and civilian objects are indiscriminate and their use is prohibited. A worm or virus that propagates uncontrollably through civilian networks is an example.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'indiscriminate weapons,worm,virus,uncontrolled propagation' },
    { num: 'Rule 142', title: 'Weapons causing unnecessary suffering', content: 'Cyber weapons designed or modified to cause effects equivalent to superfluous injury or unnecessary suffering to combatants are prohibited.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'unnecessary suffering,superfluous injury,prohibition,combatants' },
    { num: 'Rule 143', title: 'ENMOD Convention applicability', content: 'The Environmental Modification Convention (ENMOD) prohibits the military or hostile use of environmental modification techniques, including cyber techniques, that have widespread, long-lasting, or severe effects.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'ENMOD,environmental modification,military use,prohibited techniques' },
    { num: 'Rule 144', title: 'Advance warning', content: 'Effective advance warning must be given of cyber attacks which may affect the civilian population, unless circumstances do not permit.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'advance warning,civilian population,notification,circumstances' },
    { num: 'Rule 145', title: 'Choice of means to minimize harm', content: 'When a choice is possible between several military objectives for obtaining a similar military advantage by cyber means, the objective to be selected is that the attack on which may be expected to cause the least danger to civilian lives and civilian objects.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'minimize harm,target selection,civilian lives,military advantage' },
    { num: 'Rule 146', title: 'Cancellation or suspension of attack', content: 'A cyber attack must be cancelled or suspended if it becomes apparent that the objective is not a military one, that it is subject to special protection, or that the attack may be expected to cause excessive incidental damage.', ch: 'Chapter 20 - Conduct of Hostilities', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'cancellation,suspension,excessive damage,reassessment' },
    { num: 'Rule 147', title: 'Feigning protected status', content: 'The improper use of the distinctive emblems of the Geneva Conventions or the United Nations in cyber operations, such as using Red Cross domain names or digital identifiers to mask military cyber operations, constitutes perfidy when done to kill, injure, or capture.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'perfidy,emblems,Red Cross,United Nations,deception' },
    { num: 'Rule 148', title: 'Parlementaire digital communications', content: 'A person authorized to negotiate under a flag of truce (parlementaire), including through digital communications, is inviolable. Intercepting or interfering with such communications violates the law of armed conflict.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'parlementaire,flag of truce,negotiations,inviolability' },
    { num: 'Rule 149', title: 'Armistice and cyber ceasefire', content: 'An armistice or ceasefire agreement may include provisions relating to cyber operations. Parties must comply with such provisions, including any requirement to cease offensive cyber operations.', ch: 'Chapter 22 - Means and Methods', part: 'Part IV - Law of Cyber Armed Conflict', kw: 'armistice,ceasefire,cyber operations,compliance' },
  ];

  const allRules = [...rules, ...additionalRules];

  const insertMany = db.transaction(() => {
    for (const rule of allRules) {
      insertArticle.run(srcId, rule.num, rule.title, rule.content, rule.ch, rule.part, rule.kw);
    }
  });
  insertMany();

  console.log(`    Tallinn Manual 2.0: ${allRules.length} rules (summaries)`);
}
